# solution.py
"""Team_Tactics / Team Collaboration Manager.

A thread-safe, in-memory collaboration platform that lets a team of
agents (or humans) coordinate work: register users, run projects, track
tasks, exchange messages with attachments, measure individual and team
performance, and export reports as CSV or PDF.

The module is intentionally dependency-free (standard library only) so it
can be embedded anywhere.  All public read methods return defensive deep
copies so callers can never mutate the manager's internal state by
accident.  Every mutating operation is serialized through a single shared
lock, making the manager safe to use from multiple threads.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Role a user can hold within the collaboration platform."""

    MEMBER = "member"
    ADMIN = "admin"
    MANAGER = "manager"
    VIEWER = "viewer"


class TaskStatus(Enum):
    """Lifecycle state of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Data model
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A member of the collaboration platform."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A unit of work owned by a user and containing tasks."""

    id: int
    name: str
    description: str
    owner_id: int
    start_date: datetime
    end_date: datetime
    created_at: datetime


@dataclass
class Task:
    """A single piece of work that lives inside a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    """A message posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating one user gives another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Shared data context
# ---------------------------------------------------------------------------
class _Context:
    """Holds all shared state, the global id counter and the shared lock.

    Every service receives the same ``_Context`` instance so they operate on
    the same data behind the same lock.  Internal lookup helpers raise the
    appropriate :class:`NotFoundError` and return *live* objects (never
    copies) for use inside mutating operations.
    """

    def __init__(self, now: Callable[[], datetime]):
        self.now = now
        self.lock = threading.RLock()

        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Secondary indexes -------------------------------------------------
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.project_tasks: Dict[int, set] = {}
        self.assignee_tasks: Dict[int, set] = {}
        self.project_messages: Dict[int, set] = {}
        self.task_messages: Dict[int, set] = {}
        self.ratee_ratings: Dict[int, List[int]] = {}

        self._counter = 0

    # -- id allocation ------------------------------------------------------
    def next_id(self) -> int:
        self._counter += 1
        return self._counter

    # -- required lookups ---------------------------------------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    # -- collection helpers -------------------------------------------------
    def tasks_for_project(self, project_id: int) -> List[Task]:
        ids = self.project_tasks.get(project_id, set())
        return sorted(
            (self.tasks[tid] for tid in ids if tid in self.tasks),
            key=lambda t: t.id,
        )

    def tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = self.assignee_tasks.get(user_id, set())
        return sorted(
            (self.tasks[tid] for tid in ids if tid in self.tasks),
            key=lambda t: t.id,
        )

    def ratings_for_ratee(self, user_id: int) -> List[Rating]:
        ids = self.ratee_ratings.get(user_id, [])
        return [self.ratings[rid] for rid in ids if rid in self.ratings]

    # -- index maintenance --------------------------------------------------
    def _detach_assignee(self, task: Task) -> None:
        if task.assignee_id is not None:
            bucket = self.assignee_tasks.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task.id)

    def _attach_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.assignee_tasks.setdefault(assignee_id, set()).add(task.id)


# ---------------------------------------------------------------------------
# Service base
# ---------------------------------------------------------------------------
class _Service:
    """Base class giving every service the shared lock and context."""

    def __init__(self, ctx: _Context):
        self._ctx = ctx
        self._lock = ctx.lock


def _copy(value):
    """Return a deep copy so callers cannot mutate internal state."""

    return copy.deepcopy(value)


def _validate_email(email: str) -> str:
    if not isinstance(email, str):
        raise ValidationError("email must be a string")
    cleaned = email.strip()
    if not cleaned or "@" not in cleaned:
        raise ValidationError("invalid email address")
    return cleaned


def _validate_non_empty(value: str, label: str) -> str:
    if not isinstance(value, str):
        raise ValidationError("{0} must be a string".format(label))
    cleaned = value.strip()
    if not cleaned:
        raise ValidationError("{0} must not be empty".format(label))
    return cleaned


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class UserService(_Service):
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            name = _validate_non_empty(username, "username")
            mail = _validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if name.lower() in self._ctx.username_index:
                raise DuplicateError("username already in use")
            if mail.lower() in self._ctx.email_index:
                raise DuplicateError("email already in use")

            user = User(
                id=self._ctx.next_id(),
                username=name,
                email=mail,
                role=role,
                created_at=self._ctx.now(),
            )
            self._ctx.users[user.id] = user
            self._ctx.username_index[name.lower()] = user.id
            self._ctx.email_index[mail.lower()] = user.id
            return _copy(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return _copy(self._ctx.require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                _copy(self._ctx.users[uid])
                for uid in sorted(self._ctx.users)
            ]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._ctx.require_user(user_id)

            if username is not None:
                name = _validate_non_empty(username, "username")
                key = name.lower()
                holder = self._ctx.username_index.get(key)
                if holder is not None and holder != user_id:
                    raise DuplicateError("username already in use")
                del self._ctx.username_index[user.username.lower()]
                self._ctx.username_index[key] = user_id
                user.username = name

            if email is not None:
                mail = _validate_email(email)
                key = mail.lower()
                holder = self._ctx.email_index.get(key)
                if holder is not None and holder != user_id:
                    raise DuplicateError("email already in use")
                del self._ctx.email_index[user.email.lower()]
                self._ctx.email_index[key] = user_id
                user.email = mail

            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                user.role = role

            return _copy(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._ctx.require_user(user_id)

            for project in self._ctx.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user still owns a project")

            for task in self._ctx.tasks_for_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")

            del self._ctx.users[user_id]
            self._ctx.username_index.pop(user.username.lower(), None)
            self._ctx.email_index.pop(user.email.lower(), None)
            self._ctx.assignee_tasks.pop(user_id, None)


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class ProjectService(_Service):
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            clean_name = _validate_non_empty(name, "project name")
            self._ctx.require_user(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")

            project = Project(
                id=self._ctx.next_id(),
                name=clean_name,
                description=description or "",
                owner_id=owner_id,
                start_date=start_date,
                end_date=end_date,
                created_at=self._ctx.now(),
            )
            self._ctx.projects[project.id] = project
            self._ctx.project_tasks.setdefault(project.id, set())
            self._ctx.project_messages.setdefault(project.id, set())
            return _copy(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return _copy(self._ctx.require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                _copy(self._ctx.projects[pid])
                for pid in sorted(self._ctx.projects)
            ]

    def update_project(
        self, project_id, name=None, start_date=None, end_date=None,
        description=None,
    ) -> Project:
        with self._lock:
            project = self._ctx.require_project(project_id)

            if name is not None:
                project.name = _validate_non_empty(name, "project name")

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")
            project.start_date = new_start
            project.end_date = new_end

            if description is not None:
                project.description = description

            return _copy(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._ctx.require_project(project_id)

            for task_id in list(self._ctx.project_tasks.get(project_id, set())):
                task = self._ctx.tasks.get(task_id)
                if task is not None:
                    self._ctx._detach_assignee(task)
                    for msg_id in list(self._ctx.task_messages.get(task_id, set())):
                        self._discard_message(msg_id)
                    self._ctx.task_messages.pop(task_id, None)
                    del self._ctx.tasks[task_id]

            for msg_id in list(self._ctx.project_messages.get(project_id, set())):
                self._discard_message(msg_id)

            self._ctx.project_tasks.pop(project_id, None)
            self._ctx.project_messages.pop(project_id, None)
            del self._ctx.projects[project_id]

    def _discard_message(self, message_id) -> None:
        message = self._ctx.messages.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self._ctx.project_messages.get(message.project_id)
            if bucket is not None:
                bucket.discard(message_id)
        if message.task_id is not None:
            bucket = self._ctx.task_messages.get(message.task_id)
            if bucket is not None:
                bucket.discard(message_id)


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class TaskService(_Service):
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None
    ) -> Task:
        with self._lock:
            project = self._ctx.require_project(project_id)
            clean_title = _validate_non_empty(title, "task title")
            if assignee_id is not None:
                self._ctx.require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task = Task(
                id=self._ctx.next_id(),
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=None,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._ctx.now(),
            )
            self._ctx.tasks[task.id] = task
            self._ctx.project_tasks.setdefault(project_id, set()).add(task.id)
            self._ctx._attach_assignee(task, assignee_id)
            return _copy(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return _copy(self._ctx.require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._ctx.require_project(project_id)
            return [_copy(t) for t in self._ctx.tasks_for_project(project_id)]

    def list_tasks_by_assignee(self, assignee_id) -> List[Task]:
        with self._lock:
            self._ctx.require_user(assignee_id)
            return [_copy(t) for t in self._ctx.tasks_for_assignee(assignee_id)]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.require_user(assignee_id)
            self._ctx._detach_assignee(task)
            self._ctx._attach_assignee(task, assignee_id)
            return _copy(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx.require_user(new_assignee_id)
            self._ctx._detach_assignee(task)
            self._ctx._attach_assignee(task, new_assignee_id)
            return _copy(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            self._ctx._detach_assignee(task)
            task.assignee_id = None
            return _copy(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if deadline is not None:
                project = self._ctx.require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return _copy(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._ctx.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._ctx.now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return _copy(task)


# ---------------------------------------------------------------------------
# Message service
# ---------------------------------------------------------------------------
class MessageService(_Service):
    def post_message(
        self, author_id, body, project_id=None, task_id=None,
        parent_id=None, attachments=None,
    ) -> Message:
        with self._lock:
            self._ctx.require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._ctx.require_project(project_id)
            if task_id is not None:
                self._ctx.require_task(task_id)
            if parent_id is not None:
                self._ctx.require_message(parent_id)

            built = self._build_attachments(attachments, author_id)
            text = body if isinstance(body, str) else ""
            if not text.strip() and not built:
                raise ValidationError("message requires body or attachment")

            message = Message(
                id=self._ctx.next_id(),
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=self._ctx.now(),
                edited_at=None,
            )
            self._ctx.messages[message.id] = message
            if project_id is not None:
                self._ctx.project_messages.setdefault(project_id, set()).add(
                    message.id
                )
            if task_id is not None:
                self._ctx.task_messages.setdefault(task_id, set()).add(
                    message.id
                )
            return _copy(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            text = new_body if isinstance(new_body, str) else ""
            if not text.strip() and not message.attachments:
                raise ValidationError("message requires body or attachment")
            message.body = text
            message.edited_at = self._ctx.now()
            return _copy(message)

    def add_attachment(self, message_id, uploader_id, filename, data) -> Message:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            clean_name = _validate_non_empty(filename, "filename")
            message.attachments.append(
                Attachment(
                    filename=clean_name,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._ctx.now(),
                )
            )
            return _copy(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._ctx.require_project(project_id)
            ids = self._ctx.project_messages.get(project_id, set())
            return [
                _copy(self._ctx.messages[mid])
                for mid in sorted(ids)
                if mid in self._ctx.messages
            ]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._ctx.require_task(task_id)
            ids = self._ctx.task_messages.get(task_id, set())
            return [
                _copy(self._ctx.messages[mid])
                for mid in sorted(ids)
                if mid in self._ctx.messages
            ]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._ctx.require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            if message.project_id is not None:
                bucket = self._ctx.project_messages.get(message.project_id)
                if bucket is not None:
                    bucket.discard(message_id)
            if message.task_id is not None:
                bucket = self._ctx.task_messages.get(message.task_id)
                if bucket is not None:
                    bucket.discard(message_id)
            del self._ctx.messages[message_id]

    def _build_attachments(self, attachments, author_id) -> List[Attachment]:
        built: List[Attachment] = []
        if not attachments:
            return built
        now = self._ctx.now()
        for entry in attachments:
            filename, data = entry
            clean_name = _validate_non_empty(filename, "filename")
            built.append(
                Attachment(
                    filename=clean_name,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
            )
        return built


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class PerformanceService(_Service):
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._ctx.require_user(user_id)
            durations = self._completion_durations(
                self._ctx.tasks_for_assignee(user_id)
            )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        with self._lock:
            self._ctx.require_user(rater_id)
            self._ctx.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1-5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._ctx.require_task(task_id)

            rating = Rating(
                id=self._ctx.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._ctx.now(),
            )
            self._ctx.ratings[rating.id] = rating
            self._ctx.ratee_ratings.setdefault(ratee_id, []).append(rating.id)
            return _copy(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            ratings = self._ctx.ratings_for_ratee(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [_copy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            durations = self._completion_durations(tasks)
            avg_time = (
                sum(durations) / len(durations) if durations else None
            )
            ratings = self._ctx.ratings_for_ratee(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    @staticmethod
    def _completion_durations(tasks) -> List[float]:
        durations = []
        for task in tasks:
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations


# ---------------------------------------------------------------------------
# Report service
# ---------------------------------------------------------------------------
class ReportService(_Service):
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self._ctx.require_project(project_id)
            tasks = self._ctx.tasks_for_project(project_id)
            now = self._ctx.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            assignee_tasks: Dict[int, List[Task]] = {}
            completed = 0

            for task in tasks:
                status_counts[task.status.value] += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                if (
                    task.status != TaskStatus.COMPLETED
                    and task.deadline is not None
                    and task.deadline < now
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    assignee_tasks.setdefault(task.assignee_id, []).append(task)

            for assignee_id, subset in assignee_tasks.items():
                per_assignee[assignee_id] = self._task_stats(subset)

            total = len(tasks)
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._ctx.require_project(project_id)
                scoped = self._ctx.tasks_for_project(project_id)
            else:
                scoped = list(self._ctx.tasks.values())

            by_assignee: Dict[int, List[Task]] = {}
            for task in scoped:
                if task.assignee_id is not None:
                    by_assignee.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(by_assignee):
                stats = self._task_stats(by_assignee[user_id])
                ratings = self._ctx.ratings_for_ratee(user_id)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                row = {"user_id": user_id}
                row.update(stats)
                row["rating_count"] = rating_count
                row["rating_average"] = rating_average
                rows.append(row)

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._ctx.require_user(user_id)
            tasks = self._ctx.tasks_for_assignee(user_id)
            stats = self._task_stats(tasks)
            ratings = self._ctx.ratings_for_ratee(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            task_rows = [
                {
                    "id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": stats["total_tasks"],
                "completed_tasks": stats["completed_tasks"],
                "in_progress_tasks": stats["in_progress_tasks"],
                "not_started_tasks": stats["not_started_tasks"],
                "completion_rate": stats["completion_rate"],
                "average_completion_time": stats["average_completion_time"],
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    def export_report(self, report, report_format) -> object:
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if report_format == ReportFormat.CSV:
                return self._to_csv(report)
            return self._to_pdf(report)

    # -- helpers ------------------------------------------------------------
    @staticmethod
    def _task_stats(tasks) -> dict:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(
            1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
        )
        not_started = sum(
            1 for t in tasks if t.status == TaskStatus.NOT_STARTED
        )
        durations = PerformanceService._completion_durations(tasks)
        avg_time = sum(durations) / len(durations) if durations else None
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": avg_time,
        }

    @staticmethod
    def _to_csv(report) -> str:
        out = io.StringIO()
        writer = csv.writer(out)
        rtype = report.get("report_type")

        if rtype == ReportType.TEAM_PERFORMANCE.value:
            columns = [
                "user_id", "total_tasks", "completed_tasks",
                "in_progress_tasks", "not_started_tasks", "completion_rate",
                "average_completion_time", "rating_count", "rating_average",
            ]
            writer.writerow(columns)
            for row in report.get("rows", []):
                writer.writerow([row.get(col, "") for col in columns])

        elif rtype == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", report.get("project_id", "")])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            writer.writerow(
                ["completion_rate", report.get("completion_rate", 0.0)]
            )
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
            for status_value, count in report.get("status_counts", {}).items():
                writer.writerow(["status:" + str(status_value), count])
            for assignee_id, stats in report.get("per_assignee", {}).items():
                value = (
                    stats.get("completed_tasks")
                    if isinstance(stats, dict)
                    else stats
                )
                writer.writerow(["assignee:" + str(assignee_id), value])

        elif rtype == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(["task_id", "title", "status", "project_id"])
            for task in report.get("tasks", []):
                writer.writerow([
                    task.get("id", ""),
                    task.get("title", ""),
                    task.get("status", ""),
                    task.get("project_id", ""),
                ])

        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, value])

        return out.getvalue()

    @staticmethod
    def _to_pdf(report) -> bytes:
        lines = ReportService._report_lines(report)
        return _render_pdf(lines)

    @staticmethod
    def _report_lines(report) -> List[str]:
        lines = ["Report: " + str(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, (list, dict)):
                lines.append("{0}: {1} entries".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines


# ---------------------------------------------------------------------------
# Minimal PDF renderer
# ---------------------------------------------------------------------------
def _render_pdf(lines) -> bytes:
    """Build a tiny, structurally valid PDF document from text lines."""

    def escape(text):
        return (
            str(text)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    safe_lines = list(lines) if lines else [""]
    ops = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    for index, line in enumerate(safe_lines):
        if index == 0:
            ops.append("({0}) Tj".format(escape(line)))
        else:
            ops.append("T*")
            ops.append("({0}) Tj".format(escape(line)))
    ops.append("ET")
    stream = "\n".join(ops)

    objects = [
        "<< /Type /Catalog /Pages 2 0 R >>",
        "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            "/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        "<< /Length {0} >>\nstream\n{1}\nendstream".format(
            len(stream.encode("latin-1")), stream
        ),
        "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    body = "%PDF-1.4\n"
    offsets = []
    for number, obj in enumerate(objects, start=1):
        offsets.append(len(body.encode("latin-1")))
        body += "{0} 0 obj\n{1}\nendobj\n".format(number, obj)

    xref_offset = len(body.encode("latin-1"))
    count = len(objects) + 1
    xref = "xref\n0 {0}\n0000000000 65535 f \n".format(count)
    for offset in offsets:
        xref += "{0:010d} 00000 n \n".format(offset)
    trailer = (
        "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF".format(
            count, xref_offset
        )
    )
    return (body + xref + trailer).encode("latin-1")


