class TeamCollaborationManager:
    """Facade coordinating every collaboration service.

    All services share one lock and one data context, so the manager is
    safe to use concurrently and ids are globally unique across entity
    types.  A ``now`` callable can be injected for deterministic testing.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._now = now if now is not None else datetime.now
        self._ctx = _Context(self._now)
        self._lock = self._ctx.lock

        self.users = UserService(self._ctx)
        self.projects = ProjectService(self._ctx)
        self.tasks = TaskService(self._ctx)
        self.messages = MessageService(self._ctx)
        self.performance = PerformanceService(self._ctx)
        self.reports = ReportService(self._ctx)

    # -- user management ----------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        return self.users.register_user(username, email, role)

